const message = $node['Slack - Message Trigger'].json.text;
const question = message.replace(/@smartdoc/gi, '').trim();
return {
  question: question,
  timestamp: $node['Slack - Message Trigger'].json.ts,
  channelId: $node['Slack - Message Trigger'].json.channelId
};

const api = $node['HTTP - Query SmartDocAI'].json || {};
const answer = String(api.answer || '').trim();
const sources = Array.isArray(api.sources) ? api.sources : [];

const isNoInfo =
  !answer ||
  /i don't have enough information/i.test(answer) ||
  /khong co du thong tin|không có đủ thông tin/i.test(answer) ||
  sources.length === 0;

const rows = $input.all().map((item) => item.json);
const activeRows = rows.filter((row) => {
  const key = String(row.key || '').trim().toLowerCase();
  const enabled = String(row.enabled || '').trim().toLowerCase();
  return key === 'slack_reply' && enabled === 'true';
});

const foundRow =
  activeRows.find((row) => /da tim duoc|đã tìm được|found/i.test(String(row.intro || ''))) ||
  activeRows[0] ||
  {};

const notFoundRow =
  activeRows.find((row) => /chua tim duoc|chưa tìm được|không tìm được|not found/i.test(String(row.intro || ''))) ||
  activeRows[1] ||
  activeRows[0] ||
  {};

const selectedTemplate = isNoInfo ? notFoundRow : foundRow;

const messageParts = [selectedTemplate.intro || ''];
if (!isNoInfo) {
  messageParts.push(answer);
}
if (selectedTemplate.body) {
  messageParts.push(selectedTemplate.body);
}
if (selectedTemplate.footer) {
  messageParts.push(selectedTemplate.footer);
}

return {
  question: $node['Code - Extract Question'].json.question,
  timestamp: $node['Code - Extract Question'].json.timestamp,
  finalText: messageParts.filter(Boolean).join('\n\n'),
  hasAnswer: !isNoInfo,
  rawAnswer: answer
};
